var NEWS = [{"arena_slug": null, "title": "Arena Network Platform Launches for 2026 Season", "slug": "arena-network-launch-2026", "body": "The Arena Network, a new national directory and calendar platform for agricultural and equine centers, officially launches for the 2026 season. The platform connects 124 arenas across 38 states with event promoters, vendors, and sponsors in a single searchable hub designed for the western and agricultural event industry. Arena managers can claim their facilities, manage events, and connect with vendors through the dashboard.", "publish_date": "2026-03-01", "is_published": true}, {"arena_slug": "westworld-scottsdale", "title": "WestWorld Announces 2026 Sun Circuit Dates", "slug": "westworld-sun-circuit-dates-2026", "body": "WestWorld of Scottsdale has confirmed the 2026 Arizona Sun Circuit will run March 20 through March 29. The annual show draws thousands of competitors across multiple western disciplines and is one of the largest events on the WestWorld calendar. Entry information and stall reservations opened January 15. WestWorld has expanded RV parking capacity to 800 spaces for this year's event.", "publish_date": "2026-01-10", "is_published": true}, {"arena_slug": "lazy-e", "title": "Lazy E Arena Completes Indoor Lighting Upgrade", "slug": "lazy-e-lighting-upgrade-2026", "body": "Lazy E Arena in Guthrie, Oklahoma has completed a full LED lighting upgrade to its main indoor arena, improving visibility for both competitors and spectators during evening performances. The $1.2 million project was completed ahead of the 2026 Cinch Timed Event Championship. The new system reduces energy consumption by 60 percent while doubling lux levels at ground level.", "publish_date": "2026-02-01", "is_published": true}, {"arena_slug": "cheyenne-frontier-days", "title": "Cheyenne Frontier Days Celebrates 130 Years", "slug": "cfd-130-years-2026", "body": "Cheyenne Frontier Days marks its 130th anniversary in 2026 with an expanded 10-day schedule running July 17 through July 26. The Daddy of 'em All will feature more than 1,200 contestants competing for over $1 million in prize money across all standard PRCA events. New this year is an expanded night show concert lineup and a dedicated Western heritage museum exhibit on the grounds.", "publish_date": "2026-03-15", "is_published": true}, {"arena_slug": "nrg-center-houston", "title": "Houston Livestock Show Breaks Attendance Record", "slug": "houston-rodeo-attendance-2026", "body": "The 2026 Houston Livestock Show and Rodeo set a new single-day attendance record on March 14, with over 85,000 visitors passing through the NRG Park gates. The three-week event continues to be the world's largest livestock show and rodeo, with over $30 million awarded in scholarships and educational commitments since its founding.", "publish_date": "2026-03-16", "is_published": true}, {"arena_slug": "tryon-equestrian", "title": "Tryon Equestrian Center Adds New Cross-Country Course", "slug": "tryon-xc-course-2026", "body": "Tryon International Equestrian Center in Mill Spring, North Carolina has unveiled a new championship-level cross-country course designed by Olympic course designer Captain Mark Phillips. The course spans 200 acres of the venue's rolling terrain and will debut at the 2026 Tryon Fall Horse Trials in October.", "publish_date": "2026-02-20", "is_published": true}, {"arena_slug": "pbiec", "title": "Wellington Winter Equestrian Festival Sets Prize Record", "slug": "wef-prize-record-2026", "body": "The 2026 Winter Equestrian Festival at the Palm Beach International Equestrian Center will offer a record $9 million in prize money across its 12-week schedule. The circuit, running January through March, draws top show jumping and hunter competitors from more than 30 countries. PBIEC recently completed a $15 million expansion adding 400 new permanent stalls.", "publish_date": "2026-01-05", "is_published": true}, {"arena_slug": "national-western-complex", "title": "National Western Stock Show Announces 2026 Headliners", "slug": "nwss-headliners-2026", "body": "The 2026 National Western Stock Show in Denver has announced its entertainment lineup for the January 10 through 26 run. The event, in its 120th year, will feature 30 different breeds in livestock competition, a PRCA rodeo series, and for the first time a dedicated ranch horse competition showcasing working ranch skills.", "publish_date": "2025-12-15", "is_published": true}, {"arena_slug": "kentucky-horse-park", "title": "Kentucky Horse Park to Host 2026 USEF National Championships", "slug": "khp-usef-nationals-2026", "body": "The Kentucky Horse Park in Lexington has been selected to host the 2026 USEF Dressage National Championships, scheduled for September. The 1,200-acre facility will utilize both the Alltech Arena and Rolex Stadium for competition, with the adjacent Campground offering 400 RV sites with full hookups for competitors traveling with their horses.", "publish_date": "2026-02-10", "is_published": true}, {"arena_slug": "south-point", "title": "South Point Announces Expanded 2026 Calendar", "slug": "south-point-calendar-2026", "body": "South Point Arena and Equestrian Center in Las Vegas has released its 2026 calendar, featuring 45 weeks of equine competition. Highlights include the South Point Futurity in May, the World Series of Team Roping finals in December, and a new monthly jackpot roping series launching in March. The venue has invested $3 million in arena footing improvements across both the main and warm-up arenas.", "publish_date": "2026-01-20", "is_published": true}, {"arena_slug": "metrapark", "title": "MetraPark Billings Prepares for 2026 NILE", "slug": "metrapark-nile-prep-2026", "body": "MetraPark in Billings, Montana is undergoing facility improvements ahead of the 2026 Northern International Livestock Exposition in October. Upgrades include new livestock handling facilities, expanded vendor space in the trade show area, and improved Wi-Fi coverage throughout the 10,000-seat First Interstate Arena. The NILE draws competitors from across the United States and Canada.", "publish_date": "2026-03-10", "is_published": true}, {"arena_slug": null, "title": "League Membership Now Open to All Agricultural Centers", "slug": "league-membership-open-2026", "body": "The League of Agricultural and Equine Centers is now accepting membership applications from arenas, fairgrounds, and equestrian facilities nationwide. Membership benefits include listing in the Arena Network directory, access to the event calendar platform, vendor and sponsor matching tools, and AI-powered event scraping for automatic calendar population. Founding members receive premium placement and a dedicated account manager for the 2026 season.", "publish_date": "2026-03-16", "is_published": true}];
